<template>
  <div>
    <div class="nav-bar-container">
      <nav class="nav" :class="{ collapsed: isHidden }">
        <!-- TOP ROW -->
        <div class="nav-header">
          <span>{{ title }}</span>
          <ion-icon :name="iconName" @click="toggleNav" id="navToggle"></ion-icon>
        </div>

        <!-- TOGGLING CONTENT -->
        <div class="nav-content" :class="{ hidden: isHidden }">
          <ul>
            <!-- Loop through the grouped pairs -->
            <div
              class="nav-col"
              v-for="(pair, groupIndex) in groupedPages"
              :key="groupIndex"
            >
              <!-- Loop through the 1 or 2 items inside that pair -->
              <li v-for="page in pair" :key="page.index">
                <router-link
                  :to="page.to"
                  class="accent-color level-three-item"
                >
                  {{ page.name }}
                </router-link>
              </li>
            </div>
          </ul>
        </div>
      </nav>
    </div>
  </div>
</template>

<script>
import pagesData from '@/data/pages.json';

export default {
  data() {
    return {
      isHidden: true,
      title: "What's inside here?",
      pages: pagesData.pages,
      navigationTitles: pagesData.titles,
    };
  },

  computed: {
    iconName() {
      return this.isHidden ? "menu-outline" : "close-outline";
    },

    groupedPages() {
      const groups = [];
      for (let i = 0; i < this.pages.length; i += 2) {
        groups.push(this.pages.slice(i, i + 2));
      }
      return groups;
    },
  },

  methods: {
    toggleNav() {
      this.isHidden = !this.isHidden;
      if (this.isHidden) {
        this.title = this.navigationTitles[
          Math.floor(Math.random() * this.navigationTitles.length)
        ];
        this.removeClickOutsideListener();
      } else {
        this.title = "Close";
        this.addClickOutsideListener();
      }
    },

    handleClickOutside(event) {
      const navElement = this.$el.querySelector('.nav');
      if (!navElement.contains(event.target)) {
        this.toggleNav();
      }
    },

    addClickOutsideListener() {
      document.addEventListener('click', this.handleClickOutside);
    },

    removeClickOutsideListener() {
      document.removeEventListener('click', this.handleClickOutside);
    },
  },

  beforeUnmount() {
    this.removeClickOutsideListener();
  },
};
</script>
