<template>
  <div class="floating-chevrons">
    <ion-icon
      id="left"
      name="chevron-back-outline"
      class="chevron left"
      :class="currentPage <= firstIndex ? 'disabled' : 'enabled'"
      @click="prevPage"
    ></ion-icon>

    <ion-icon
      id="right"
      name="chevron-forward-outline"
      class="chevron right"
      :class="currentPage === lastIndex ? 'disabled' : 'enabled'"
      @click="nextPage"
    ></ion-icon>
  </div>
</template>

<script>
import pagedata from "@/data/pages.json";

export default {
  name: "NavigationChevron",
  data() {
    const pages = pagedata.pages || [];
    return {
      currentPage: 0,
      firstIndex: pages.length > 0 ? pages[0].index : 0,
      lastIndex: pages.length > 0 ? pages.at(-1).index : 0,
    };
  },
  created() {
    this.updateCurrentPage();
  },
  watch: {
    // Watch for route changes
    $route() {
      this.updateCurrentPage();
    },
  },
  methods: {
    updateCurrentPage() {
      // Find the index of the current route in pagedata.pages
      const currentRoute = this.$route.path;
      const currentPageIndex = pagedata.pages.findIndex(
        (page) => page.to === currentRoute
      );
      if (currentPageIndex !== -1) {
        this.currentPage = currentPageIndex;
      }
    },
    prevPage() {
      if (this.currentPage > this.firstIndex) {
        this.currentPage--;
        this.$router.push(pagedata.pages[this.currentPage].to);
      }
    },
    nextPage() {
      if (this.currentPage < this.lastIndex) {
        this.currentPage++;
        this.$router.push(pagedata.pages[this.currentPage].to);
      }
    },
  },
};
</script>
