<template>
  <div class="catalog-display" ref="grid"></div>
</template>

<script>
import { all_icons } from "@/assets/icons/includes";
import catalogdata from "@/data/catalog.json";

export default {
  name: "CatalogSection",
  data() {
    const catalog_languages = catalogdata?.languages ?? [];
    const catalog_skills = catalogdata?.skills ?? [];

    return {
      catalog_data: [...catalog_languages, ...catalog_skills],
      displayedSkills: new Set(),
      gridSize: 10,
      all_icons,
    };
  },
  methods: {
    createGridItem(skill) {
      const gridBox = document.createElement('div');
      gridBox.className = 'grid-box';

      const icon = this.all_icons[skill.icon];
      gridBox.innerHTML = `
        <div class="svg-container" style="color: ${skill.brand_color};">
          <img src="${icon}" alt="${skill.name}" class="svg-icon" />
        </div>
        <span>${skill.name}</span>
      `;

      return gridBox;
    },

    getRandomAvailableSkill() {
      const availableSkills = this.catalog_data.filter(skill => !this.displayedSkills.has(skill.name));
      if (availableSkills.length === 0) {
        this.displayedSkills.clear();
        return this.catalog_data[Math.floor(Math.random() * this.catalog_data.length)];
      }
      return availableSkills[Math.floor(Math.random() * availableSkills.length)];
    },

    updateBox(box, skill) {
      box.style.opacity = 0;
      setTimeout(() => {
        const icon = this.all_icons[skill.icon];
        box.innerHTML = `
          <div class="svg-container" style="color: ${skill.brand_color};">
            <img src="${icon}" alt="${skill.name}" class="svg-icon" />
          </div>
          <span>${skill.name}</span>
        `;
        box.style.opacity = 1;
      }, 500);
    },

    updateRandomBoxes() {
      const boxes = this.$refs.grid.querySelectorAll('.grid-box');
      const numBoxesToUpdate = 1 + Math.floor(Math.random() * 4);
      const shuffledIndices = Array.from({ length: boxes.length }, (_, i) => i)
                                   .sort(() => 0.5 - Math.random());

      for (let i = 0; i < numBoxesToUpdate; i++) {
        const boxIndex = shuffledIndices[i];
        const box = boxes[boxIndex];
        const span = box.querySelector('span');
        if (!span) continue;

        const currentSkillName = span.textContent;
        this.displayedSkills.delete(currentSkillName);

        const randomSkill = this.getRandomAvailableSkill();
        if (randomSkill) {
          this.displayedSkills.add(randomSkill.name);
          this.updateBox(box, randomSkill);
        }
      }
    },

    initializeGrid() {
      const grid = this.$refs.grid;
      const shuffledSkills = [...this.catalog_data].sort(() => 0.5 - Math.random());

      for (let i = 0; i < this.gridSize; i++) {
        const skill = shuffledSkills[i];
        if (skill) {
          this.displayedSkills.add(skill.name);
          const gridItem = this.createGridItem(skill);
          grid.appendChild(gridItem);
        }
      }
    },

    startRandomUpdates() {
      this.initializeGrid();
      this.updateInterval = setInterval(this.updateRandomBoxes, 5000 + Math.random() * 7000);
    }
  },
  mounted() {
    this.startRandomUpdates();
  },
  beforeUnmount() {
    clearInterval(this.updateInterval);
  }
};
</script>

